/**
 * dashboard-route.js — client-saas /home
 *
 * Translation of the MachFiveMagnet demo dashboard (demo/index.html .demo-content)
 * into our shell: dark side-nav + light content. Built entirely from the tokenized
 * primitive kit (styles/dashboard-kit.css) — no inline styles, no demo --m5-* vars.
 *
 * Data posture (verified): only "Active Magnets" is live + owner-scoped today
 * (GET /m5t/v5/sseEtherSubscriberApp, scoped server-side by the JWT). Conversations /
 * Leads / Flow Completion have NO data model yet, and the activity/coreMeter feed is
 * unscoped — so those render as honest empty-states, not fabricated numbers. They fill
 * in as owner-scoped /stats endpoints are added.
 */

import AuthController from '../services/AuthController.js';

const emptyState = (icon, msg) =>
  `<div class="m5t-empty"><span class="material-symbols-outlined" aria-hidden="true">${icon}</span><p>${msg}</p></div>`;

const statCard = ({ icon, label, valueId, value = '—', subId, sub = '' }) => `
  <div class="stat-card">
    <div class="stat-header">
      <span class="material-symbols-outlined stat-icon" aria-hidden="true">${icon}</span>
      <span class="stat-label">${label}</span>
    </div>
    <div class="stat-value"${valueId ? ` id="${valueId}"` : ''}>${value}</div>
    <div class="stat-change"><span class="stat-sublabel"${subId ? ` id="${subId}"` : ''}>${sub}</span></div>
  </div>`;

const chartCard = (icon, title, { wide = false, full = false, controls = false } = {}) => `
  <div class="dashboard-card${wide ? ' chart-card-wide' : ''}${full ? ' chart-card-full' : ''}">
    <div class="card-header">
      <h2 class="card-title"><span class="material-symbols-outlined" aria-hidden="true">${icon}</span> ${title}</h2>
      ${controls ? `<div class="chart-controls">
        <button class="chart-period-btn active" type="button" data-period="7">7 Days</button>
        <button class="chart-period-btn" type="button" data-period="30">30 Days</button>
      </div>` : ''}
    </div>
    <div class="card-body">${emptyState('insights', 'Insights appear here once your magnets start capturing conversations.')}</div>
  </div>`;

export function render() {
  return `
    <div class="page-shell" data-section="home">
      <div class="page-header">
        <div class="page-header-text">
          <h1 class="page-title">Dashboard</h1>
          <p class="page-description">Your magnets, conversations, and lead performance at a glance.</p>
        </div>
        <a class="btn btn-primary" href="#/magnets">
          <span class="material-symbols-outlined" aria-hidden="true">add</span>
          New Magnet
        </a>
      </div>

      <div class="stats-grid">
        ${statCard({ icon: 'widgets', label: 'Active Magnets', valueId: 'stat-active-magnets', subId: 'stat-active-magnets-sub', sub: 'Loading…' })}
        ${statCard({ icon: 'forum', label: 'Conversations Started', sub: 'Coming soon' })}
        ${statCard({ icon: 'person_add', label: 'Leads Captured', sub: 'Coming soon' })}
        ${statCard({ icon: 'check_circle', label: 'Flow Completion Rate', sub: 'Coming soon' })}
      </div>

      <div class="charts-section">
        ${chartCard('show_chart', 'Conversation Trends', { wide: true, controls: true })}
        <div class="charts-grid">
          ${chartCard('filter_alt', 'Completion Funnel')}
          ${chartCard('source', 'Traffic Sources')}
          ${chartCard('bar_chart', 'Magnet Performance', { full: true })}
        </div>
      </div>

      <div class="content-grid">
        <div class="dashboard-card">
          <div class="card-header">
            <h2 class="card-title"><span class="material-symbols-outlined" aria-hidden="true">bolt</span> Recent Interactions</h2>
            <span class="live-indicator"><span class="pulse-dot"></span> Live</span>
          </div>
          <div class="card-body">
            ${emptyState('sensors', "No interactions yet — they'll stream in live as visitors engage your magnets.")}
          </div>
        </div>
        <div class="dashboard-card">
          <div class="card-header">
            <h2 class="card-title"><span class="material-symbols-outlined" aria-hidden="true">group</span> Recent Leads</h2>
            <a class="view-all-link" href="#/conversations">View all →</a>
          </div>
          <div class="card-body">
            ${emptyState('contacts', 'No leads captured yet. Publish a magnet to start collecting and scoring leads.')}
          </div>
        </div>
      </div>
    </div>`;
}

/**
 * Progressive enhancement: fill the one genuinely-live KPI (Active Magnets) from the
 * owner-scoped magnets endpoint. Any failure degrades to an em-dash — never a crash,
 * never a fabricated/cross-tenant number.
 */
export async function init() {
  const valueEl = document.getElementById('stat-active-magnets');
  const subEl = document.getElementById('stat-active-magnets-sub');
  if (!valueEl) return;

  try {
    const base = AuthController.getConfig?.().BASE_URL || '';
    const res = await fetch(`${base}/m5t/v5/sseEtherSubscriberApp`); // mvvLegit injects the Bearer
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    const json = await res.json();
    const magnets = Array.isArray(json?.data) ? json.data : [];

    const active = magnets.filter((m) => m.status === 'ENABLED').length;
    valueEl.textContent = String(active);

    // "Across N domains" — distinct active hostnames across app_domains JSONB (shape-tolerant).
    const domains = new Set();
    magnets.forEach((m) => {
      const list = Array.isArray(m.app_domains) ? m.app_domains : [];
      list.forEach((d) => {
        const host = typeof d === 'string' ? d : (d && (d.domain || d.host));
        if (host && (typeof d === 'string' || d.active !== false)) domains.add(String(host).toLowerCase());
      });
    });
    if (subEl) {
      subEl.textContent = domains.size
        ? `Across ${domains.size} domain${domains.size === 1 ? '' : 's'}`
        : (active ? 'No domains configured' : 'No magnets yet');
    }
  } catch (err) {
    console.warn('[dashboard] Active Magnets fetch failed:', err);
    valueEl.textContent = '—';
    if (subEl) subEl.textContent = 'Unavailable';
  }
}

export default { render, init };
